import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { resolve } from "path";
import { Observable, observable } from "rxjs";
import { AlertService } from "src/app/core/services/alert.service";
import { ClientService } from "src/app/core/services/client.service";
import { LoanApplicationsService } from "src/app/core/services/loan-applications.service";
import { ClientInfo } from "src/app/views/Models/Client/ClientInfo";
import { GetLoanApplicationResponse } from "src/app/views/Models/Loan/GetLoanApplication";
import { SearchResult } from "src/app/views/Models/References/SearchResult";
import { FormStatus } from "src/app/views/Models/forms/formStatus";
interface pageData {
  client: ClientInfo;
  loanApplication: GetLoanApplicationResponse;
}
@Component({
  selector: "app-cancel-loan-application-rejection",
  templateUrl: "./cancel-loan-application-rejection.page.html",
  styleUrls: ["./cancel-loan-application-rejection.page.scss"],
})
export class CancelLoanApplicationRejectionPage implements OnInit {
  constructor(
    private formBuilder: FormBuilder,
    private clientService: ClientService,
    private loanApplicationsService: LoanApplicationsService,
    private alertService: AlertService
  ) {}

  //#region Variables
  showLoader: boolean = false;
  searchComponentVisible: boolean = true;
  pageData: Promise<pageData>;
  //#endregion

  ngOnInit() {}
  cancellationRejectionForm: FormGroup = this.formBuilder.group({
    notes: [null],
  });

  async clientSelected(userInfo: SearchResult) {
    this.pageData = new Promise<pageData>(async (resolve) => {
      try {
        this.showLoader = true;
        const client = await this.clientService.getClientByClientKey(
          userInfo.client_key
        );
        const loanApplication =
          await this.loanApplicationsService.getApplicationKey(
            userInfo.application_key
          );
        this.searchComponentVisible = false;
        const data: pageData = {
          client: client,
          loanApplication: loanApplication,
        };
        this.showLoader = false;
        resolve(data);
      } catch (error) {
        console.error("Error fetching data:", error);
        this.showLoader = false;
        this.alertService.showAlertError(error?.error, false);
        resolve(null);
      }
    });
  }

  backButton() {
    this.searchComponentVisible = true;
    this.pageData = null;
    this.cancellationRejectionForm.patchValue({
      notes: null,
    });
  }

  async cancelLoanApplicationRejection() {
    if (!(await this.alertService.SaveAlert())) return;
    try {
      let requestObject: { applicationKey: number; notes: string } = {
        applicationKey: (await this.pageData).loanApplication.applicationKey,
        notes: this.cancellationRejectionForm.value.notes,
      };
      console.log(requestObject.notes);
      this.showLoader = true;
      await this.loanApplicationsService.cancelApplicationRejection(
        requestObject.applicationKey,
        requestObject.notes
      );
      this.showLoader = false;
      this.alertService.showAlertConfirm("تم التعديل بنجاح", true);
    } catch (error) {
      this.showLoader = false;
      this.alertService.showAlertError(error.error, false);
    }
  }
}
